 38→// ── Reusable small components ──
 39→const InputField: React.FC<{ label: string; value: string; onChange: (v: string) => void; placeholder?: string; required?: boolean; type?: string }> = ({ label, value, onChange, placeholder, required, type = 'text' }) => (
 40→  <div>
