 42→    <input type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder}
 43→      className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
 44→  </div>
 45→);
 46→
 47→const TextArea: React.FC<{ label: string; value: string; onChange: (v: string) => void; placeholder?: string; rows?: number }> = ({ label, value, onChange, placeholder, rows = 3 }) => (
 48→  <div>
 49→    <label className="block text-sm font-medium text-gray-300 mb-1.5">{label}</label>
 50→    <textarea value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} rows={rows}
 51→      className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors resize-none" />
 52→  </div>
