 54→
 55→const CodeBlock: React.FC<{ code: string; title: string }> = ({ code, title }) => {
 56→  const [copied, setCopied] = useState(false);
 57→  const handleCopy = () => { navigator.clipboard.writeText(code); setCopied(true); setTimeout(() => setCopied(false), 2000); };
 58→  return (
 59→    <div className="ninja-card overflow-hidden">
 60→      <div className="flex items-center justify-between px-4 py-2 border-b border-white/[0.04]">
 61→        <span className="text-xs text-gray-500 font-semibold">{title}</span>
 62→        <button onClick={handleCopy} className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-purple-400 transition-colors">
 63→          {copied ? <Check size={12} /> : <Copy size={12} />} {copied ? 'Copié' : 'Copier'}
 64→        </button>
 65→      </div>
 66→      <pre className="p-4 text-xs text-gray-300 overflow-auto max-h-80 custom-scrollbar"><code>{code}</code></pre>
 67→    </div>
 68→  );
 69→};
