 71→const ScoreRing: React.FC<{ score: number; size?: number; label?: string }> = ({ score, size = 100, label }) => {
 72→  const radius = (size - 10) / 2;
 73→  const circumference = 2 * Math.PI * radius;
 74→  const offset = circumference - (score / 100) * circumference;
 75→  const color = score >= 70 ? '#22c55e' : score >= 40 ? '#f59e0b' : '#ef4444';
 76→  return (
 77→    <div className="flex flex-col items-center gap-2">
 78→      <div className="relative" style={{ width: size, height: size }}>
 79→        <svg width={size} height={size} className="transform -rotate-90">
 80→          <circle cx={size / 2} cy={size / 2} r={radius} stroke="rgba(255,255,255,0.05)" strokeWidth="6" fill="none" />
 81→          <circle cx={size / 2} cy={size / 2} r={radius} stroke={color} strokeWidth="6" fill="none"
 82→            strokeLinecap="round" strokeDasharray={circumference} strokeDashoffset={offset}
 83→            style={{ transition: 'stroke-dashoffset 1s ease-out' }} />
 84→        </svg>
 85→        <div className="absolute inset-0 flex flex-col items-center justify-center">
 86→          <span className="text-2xl font-bold text-white">{score}</span>
 87→          <span className="text-[9px] text-gray-500 uppercase">/100</span>
 88→        </div>
 89→      </div>
 90→      {label && <span className="text-xs text-gray-400 font-medium">{label}</span>}
 91→    </div>
 92→  );
 93→};
 94→
 95→const ScoreBar: React.FC<{ label: string; score: number; color: string }> = ({ label, score, color }) => (
 96→  <div className="space-y-1.5">
 97→    <div className="flex justify-between text-xs">
 98→      <span className="text-gray-400">{label}</span>
 99→      <span className="text-gray-300 font-bold">{score}/100</span>
100→    </div>
101→    <div className="w-full h-2 bg-white/[0.04] rounded-full overflow-hidden">
102→      <div className="h-full rounded-full transition-all duration-700" style={{ width: `${score}%`, background: color }} />
103→    </div>
104→  </div>
105→);
