111→const EeatBuilder: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
112→  const [activeTab, setActiveTab] = useState<TabId>('author-bio');
113→  const [isLoading, setIsLoading] = useState(false);
114→
115→  // ── Author Bio state ──
116→  const [authorName, setAuthorName] = useState('');
117→  const [authorTitle, setAuthorTitle] = useState('');
118→  const [authorOrg, setAuthorOrg] = useState('');
119→  const [authorYears, setAuthorYears] = useState('');
120→  const [authorSpecs, setAuthorSpecs] = useState('');
121→  const [authorLinkedin, setAuthorLinkedin] = useState('');
122→  const [authorPhotoUrl, setAuthorPhotoUrl] = useState('');
123→  const [authorEducation, setAuthorEducation] = useState<Education[]>([]);
124→  const [authorCredentials, setAuthorCredentials] = useState<Credential[]>([]);
125→  const [bioResult, setBioResult] = useState<GeneratedAuthorBio | null>(null);
126→
127→  // ── About Page state ──
128→  const [orgName, setOrgName] = useState('');
129→  const [orgType, setOrgType] = useState<'Organization' | 'LocalBusiness' | 'Corporation'>('Organization');
130→  const [orgFounding, setOrgFounding] = useState('');
131→  const [orgIndustry, setOrgIndustry] = useState('');
132→  const [orgSpecs, setOrgSpecs] = useState('');
133→  const [orgServices, setOrgServices] = useState('');
134→  const [orgEmail, setOrgEmail] = useState('');
135→  const [orgSiteUrl, setOrgSiteUrl] = useState('');
136→  const [orgCity, setOrgCity] = useState('');
137→  const [orgCountry, setOrgCountry] = useState('France');
138→  const [aboutResult, setAboutResult] = useState<GeneratedAboutPage | null>(null);
139→
140→  // ── Trust Signals state ──
141→  const [trustOrgName, setTrustOrgName] = useState('');
142→  const [trustCerts, setTrustCerts] = useState('');
143→  const [trustPress, setTrustPress] = useState('');
144→  const [trustGuarantees, setTrustGuarantees] = useState('');
145→  const [trustProof, setTrustProof] = useState('');
146→  const [trustReviewPlatform, setTrustReviewPlatform] = useState('google');
147→  const [trustReviewRating, setTrustReviewRating] = useState('4.5');
148→  const [trustReviewCount, setTrustReviewCount] = useState('150');
149→  const [trustResult, setTrustResult] = useState<GeneratedTrustBlock | null>(null);
150→
151→  // ── Credentials state ──
152→  const [credName, setCredName] = useState('');
153→  const [credTitle, setCredTitle] = useState('');
154→  const [credOrg, setCredOrg] = useState('');
155→  const [credYears, setCredYears] = useState('');
156→  const [credSpecs, setCredSpecs] = useState('');
157→  const [credEducation, setCredEducation] = useState<Education[]>([]);
158→  const [credCredentials, setCredCredentials] = useState<Credential[]>([]);
159→  const [credAwards, setCredAwards] = useState<Award[]>([]);
160→  const [credResult, setCredResult] = useState<GeneratedCredentials | null>(null);
161→
162→  // ── Citation Block state ──
163→  const [citeName, setCiteName] = useState('');
164→  const [citeTitle, setCiteTitle] = useState('');
165→  const [citeOrg, setCiteOrg] = useState('');
166→  const [citeYears, setCiteYears] = useState('');
167→  const [citeSpecs, setCiteSpecs] = useState('');
168→  const [citeLinkedin, setCiteLinkedin] = useState('');
169→  const [citePhotoUrl, setCitePhotoUrl] = useState('');
170→  const [citeArticleTitle, setCiteArticleTitle] = useState('');
171→  const [citeResult, setCiteResult] = useState<GeneratedCitationBlock | null>(null);
172→
173→  // ── Audit state ──
174→  const [auditUrl, setAuditUrl] = useState('');
175→  const [auditBrand, setAuditBrand] = useState('');
176→  const [auditResult, setAuditResult] = useState<EeatAuditResult | null>(null);
177→
178→  // ── Build AuthorProfile helper ──
179→  const buildAuthorProfile = (name: string, title: string, org: string, years: string, specs: string, linkedin: string, photoUrl: string, education: Education[], credentials: Credential[], awards?: Award[], publications?: Publication[]): AuthorProfile => ({
180→    name, jobTitle: title, organization: org,
181→    yearsExperience: parseInt(years) || 5,
182→    specializations: specs.split(',').map(s => s.trim()).filter(Boolean),
183→    credentials,
184→    certifications: [],
185→    education,
186→    awards: awards || [],
187→    publications: publications || [],
188→    socialProfiles: linkedin ? [{ platform: 'linkedin' as const, url: linkedin }] : [],
189→    photoUrl: photoUrl || undefined,
190→  });
191→
192→  // ── Handlers ──
193→  const handleGenerateBio = async () => {
194→    if (!authorName || !authorTitle) return;
195→    if (!onDeductCredits(EEAT_CREDITS.authorBio)) return;
196→    setIsLoading(true); setBioResult(null);
197→    try {
198→      const profile = buildAuthorProfile(authorName, authorTitle, authorOrg, authorYears, authorSpecs, authorLinkedin, authorPhotoUrl, authorEducation, authorCredentials);
199→      const result = await generateAuthorBio(profile);
200→      setBioResult(result);
201→    } catch (e) { console.error(e); }
202→    finally { setIsLoading(false); }
203→  };
204→
205→  const handleGenerateAbout = async () => {
206→    if (!orgName || !orgEmail) return;
207→    if (!onDeductCredits(EEAT_CREDITS.aboutPage)) return;
208→    setIsLoading(true); setAboutResult(null);
209→    try {
210→      const org: OrganizationProfile = {
211→        name: orgName, type: orgType, foundingDate: orgFounding || '2020-01-01',
212→        industry: orgIndustry, specializations: orgSpecs.split(',').map(s => s.trim()).filter(Boolean),
213→        servicesOffered: orgServices.split(',').map(s => s.trim()).filter(Boolean),
214→        certifications: [], awards: [], partnerships: [], mediaAppearances: [],
215→        reviews: [], guarantees: [], accreditations: [],
216→        address: { street: '', city: orgCity, postalCode: '', country: orgCountry },
217→        email: orgEmail, socialProfiles: [], siteUrl: orgSiteUrl,
218→      };
219→      const result = await generateAboutPage(org);
220→      setAboutResult(result);
221→    } catch (e) { console.error(e); }
222→    finally { setIsLoading(false); }
223→  };
224→
225→  const handleGenerateTrust = async () => {
226→    if (!trustOrgName) return;
227→    if (!onDeductCredits(EEAT_CREDITS.trustSignals)) return;
228→    setIsLoading(true); setTrustResult(null);
229→    try {
230→      const config: TrustSignalsConfig = {
231→        certifications: trustCerts.split('\n').filter(Boolean).map(c => {
232→          const parts = c.split('|').map(s => s.trim());
233→          return { name: parts[0] || c, issuer: parts[1] || '' };
234→        }),
235→        securityBadges: [{ type: 'ssl' }, { type: 'gdpr' }, { type: 'secure_payment' }],
236→        guarantees: trustGuarantees.split('\n').filter(Boolean).map(g => ({
237→          type: 'satisfaction' as const, details: g,
238→        })),
239→        socialProof: trustProof.split('\n').filter(Boolean).map(s => ({ metric: s })),
240→        pressMentions: trustPress.split('\n').filter(Boolean).map(p => {
241→          const parts = p.split('|').map(s => s.trim());
242→          return { outlet: parts[0] || p, quote: parts[1] || undefined };
243→        }),
244→        reviews: [{ platform: trustReviewPlatform as any, rating: parseFloat(trustReviewRating) || 4.5, count: parseInt(trustReviewCount) || 100 }],
245→      };
246→      const result = await generateTrustSignals(config, trustOrgName);
247→      setTrustResult(result);
248→    } catch (e) { console.error(e); }
249→    finally { setIsLoading(false); }
250→  };
251→
252→  const handleGenerateCredentials = async () => {
253→    if (!credName || !credTitle) return;
254→    if (!onDeductCredits(EEAT_CREDITS.credentials)) return;
255→    setIsLoading(true); setCredResult(null);
256→    try {
257→      const profile = buildAuthorProfile(credName, credTitle, credOrg, credYears, credSpecs, '', '', credEducation, credCredentials, credAwards);
