input.new_string:
import { GoogleGenAI, Type, Schema } from "@google/genai";
import { EeatAuditResult } from "../../types/eeat";
import { PROMPT_EEAT_AUDIT } from "./prompts";

// ═══════════════════════════════════════════
// E-E-A-T AUDIT HISTORY (localStorage)
// ═══════════════════════════════════════════

const STORAGE_KEY = 'citedby-eeat-history';

export interface EeatAuditHistoryEntry {
  id: string;
  url: string;
  brand?: string;
  date: string;
  scores: EeatAuditResult['scores'];
  findings: EeatAuditResult['findings'];
  priorityActions: EeatAuditResult['priorityActions'];
  summary: string;
}

export interface AuditComparison {
  current: EeatAuditHistoryEntry;
  previous: EeatAuditHistoryEntry;
  deltas: {
    overall: number;
    experience: number;
    expertise: number;
    authoritativeness: number;
    trustworthiness: number;
  };
  improvedCount: number;
  regressedCount: number;
}

export const saveAuditToHistory = (result: EeatAuditResult, brand?: string): EeatAuditHistoryEntry => {
  const history = getAuditHistory();
  const entry: EeatAuditHistoryEntry = {
    id: `audit-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    url: result.url,
    brand,
    date: new Date().toISOString(),
    scores: { ...result.scores },
    findings: [...result.findings],
    priorityActions: [...result.priorityActions],
    summary: result.summary,
  };
  history.unshift(entry);
  // Keep max 50 entries
  if (history.length > 50) history.length = 50;
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(history));
  } catch (e) {
    console.warn('Failed to save audit history to localStorage:', e);
  }
  return entry;
};

export const getAuditHistory = (): EeatAuditHistoryEntry[] => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return [];
    return JSON.parse(raw) as EeatAuditHistoryEntry[];
  } catch {
    return [];
  }
};

export const getLastAuditForUrl = (url: string): EeatAuditHistoryEntry | null => {
  const history = getAuditHistory();
  // Try to match by hostname for flexibility
  let hostname: string;
  try { hostname = new URL(url).hostname; } catch { hostname = url; }
  return history.find(h => {
    try { return new URL(h.url).hostname === hostname; } catch { return h.url === url; }
  }) || null;
};

export const compareAudits = (current: EeatAuditHistoryEntry, previous: EeatAuditHistoryEntry): AuditComparison => {
  const deltas = {
    overall: current.scores.overall - previous.scores.overall,
    experience: current.scores.experience - previous.scores.experience,
    expertise: current.scores.expertise - previous.scores.expertise,
    authoritativeness: current.scores.authoritativeness - previous.scores.authoritativeness,
    trustworthiness: current.scores.trustworthiness - previous.scores.trustworthiness,
  };
  const deltaValues = [deltas.experience, deltas.expertise, deltas.authoritativeness, deltas.trustworthiness];
  return {
    current,
    previous,
    deltas,
    improvedCount: deltaValues.filter(d => d > 0).length,
    regressedCount: deltaValues.filter(d => d < 0).length,
  };
};

export const clearAuditHistory = (): void => {
  localStorage.removeItem(STORAGE_KEY);
};

