{"content":"import { GoogleGenAI, Type, Schema } from "@google/genai";
import { EeatAuditResult } from "../../types/eeat";
import { PROMPT_EEAT_AUDIT } from "./prompts";

const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

const seededScore = (seed: number, offset: number, min = 15, max = 85): number => {
  const raw = ((seed * 37 + offset * 19 + 11) * 17) % 1000;
  return min + Math.round((raw / 1000) * (max - min));
};

const fallbackSimulation = async (url: string, brandName?: string): Promise<EeatAuditResult> => {
  await new Promise(resolve => setTimeout(resolve, 2800));

  let hostname: string;
  try { hostname = new URL(url).hostname; } catch { hostname = url; }
  const brand = brandName || hostname;
  const seed = url.length + hostname.length;

  const experience = seededScore(seed, 1);
  const expertise = seededScore(seed, 2);
  const authoritativeness = seededScore(seed, 3);
  const trustworthiness = seededScore(seed, 4);
  const overall = Math.round((experience + expertise + authoritativeness + trustworthiness) / 4);

  const findings: EeatAuditResult['findings'] = [
    { category: 'experience', status: experience >= 50 ? 'present' : 'missing', element: 'Temoignages de premiere main', impact: 'high', recommendation: 'Ajouter des etudes de cas detaillees avec des resultats concrets et mesurables.' },
